<?php
$pageTitle='Document Library';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('document_library_2');
$pdo=getDB();
$folders=$pdo->query('SELECT * FROM '.table('document_folders').' WHERE status="active" ORDER BY folder_name')->fetchAll();
$categories=$pdo->query('SELECT * FROM '.table('document_categories').' WHERE status="active" ORDER BY category_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'create');
    if($action==='defaults'){$created=installDocumentDefaults($pdo);flash('success','Document defaults installed: '.$created);}
    elseif($action==='link'){linkDocumentRecord($pdo,(int)$_POST['document_library_id'],trim((string)$_POST['module_key']),trim((string)$_POST['entity_type']),(int)($_POST['entity_id']??0)?:null,trim((string)$_POST['entity_number']),trim((string)$_POST['link_notes']));flash('success','Document linked to record.');}
    else{$file=dmsUploadDocumentFile('document_file');createDocumentLibraryRecord($pdo,$_POST,$file);flash('success','Document created.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'document-library']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/document-library.php');
}
$where='1=1';$params=[];
if(!empty($_GET['module'])){$where.=' AND dl.module_key=?';$params[]=(string)$_GET['module'];}
if(!empty($_GET['q'])){$where.=' AND (dl.title LIKE ? OR dl.document_number LIKE ? OR dl.tags LIKE ?)';$term='%'.(string)$_GET['q'].'%';array_push($params,$term,$term,$term);}
$stmt=$pdo->prepare('SELECT dl.*,df.folder_name,dc.category_name,u.email uploaded_email FROM '.table('document_library').' dl LEFT JOIN '.table('document_folders').' df ON df.id=dl.folder_id LEFT JOIN '.table('document_categories').' dc ON dc.id=dl.category_id LEFT JOIN '.table('users').' u ON u.id=dl.uploaded_by WHERE '.$where.' ORDER BY dl.created_at DESC LIMIT 300');
$stmt->execute($params);$docs=$stmt->fetchAll();
$stats=[
 'documents'=>(int)$pdo->query('SELECT COUNT(*) FROM '.table('document_library'))->fetchColumn(),
 'pending_approval'=>(int)$pdo->query('SELECT COUNT(*) FROM '.table('document_library').' WHERE approval_status="pending"')->fetchColumn(),
 'expiring_soon'=>(int)$pdo->query('SELECT COUNT(*) FROM '.table('document_library').' WHERE expiry_date IS NOT NULL AND expiry_date<=DATE_ADD(CURDATE(), INTERVAL '.(int)setting('document_default_expiry_alert_days','30').' DAY)')->fetchColumn(),
 'active_alerts'=>(int)$pdo->query('SELECT COUNT(*) FROM '.table('document_expiry_alerts').' WHERE status="open"')->fetchColumn(),
];
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Central Document Control</div><h2 class="h4 mb-1">Document Management System 2.0</h2><p class="text-secondary mb-0">Controlled library for company, customer, supplier, employee, product, invoice, PO, contract and compliance documents.</p></div><form method="post"><input type="hidden" name="action" value="defaults"><button class="btn btn-brand">Install DMS Defaults</button></form></div>
<div class="row g-4 mb-4"><?php foreach($stats as $k=>$v): ?><div class="col-md-3"><div class="card-admin p-4"><div class="erp-kicker"><?php echo esc(ucwords(str_replace('_',' ',$k))); ?></div><div class="metric-sm"><?php echo (int)$v; ?></div></div></div><?php endforeach; ?></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" enctype="multipart/form-data" class="card-admin p-4 mb-4"><h2 class="h5 mb-3">Upload Document</h2><input class="form-control mb-2" name="title" placeholder="Document title" required><select class="form-select mb-2" name="folder_id"><option value="">No folder</option><?php foreach($folders as $f): ?><option value="<?php echo (int)$f['id']; ?>"><?php echo esc($f['folder_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="category_id"><option value="">No category</option><?php foreach($categories as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['category_name']); ?></option><?php endforeach; ?></select><select class="form-select mb-2" name="module_key"><?php foreach(documentModuleOptions() as $k=>$v): ?><option value="<?php echo esc($k); ?>"><?php echo esc($v); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="document_type" placeholder="trade_license / contract / invoice"><div class="row g-2"><div class="col-6"><input class="form-control" name="linked_entity_type" placeholder="customer"></div><div class="col-6"><input class="form-control" type="number" name="linked_entity_id" placeholder="ID"></div></div><div class="row g-2 mt-2"><div class="col-6"><input class="form-control" type="date" name="expiry_date"></div><div class="col-6"><input class="form-control" type="date" name="review_date"></div></div><select class="form-select my-2" name="confidentiality"><option>public</option><option selected>internal</option><option>restricted</option><option>confidential</option></select><select class="form-select mb-2" name="requires_approval"><option value="0">No approval</option><option value="1">Require approval</option></select><input class="form-control mb-2" name="tags" placeholder="tags"><textarea class="form-control mb-2" name="description" rows="3" placeholder="Description"></textarea><input class="form-control mb-3" type="file" name="document_file"><button class="btn btn-brand w-100">Create Document</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="link"><h2 class="h5 mb-3">Link Existing Document</h2><select class="form-select mb-2" name="document_library_id"><?php foreach($docs as $d): ?><option value="<?php echo (int)$d['id']; ?>"><?php echo esc($d['document_number'].' · '.$d['title']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="module_key" placeholder="finance / customer"><input class="form-control mb-2" name="entity_type" placeholder="invoice / supplier"><input class="form-control mb-2" type="number" name="entity_id" placeholder="Entity ID"><input class="form-control mb-2" name="entity_number" placeholder="Entity number"><textarea class="form-control mb-3" name="link_notes" rows="2"></textarea><button class="btn btn-outline-primary w-100">Link</button></form></div><div class="col-xl-8"><form class="card-admin p-3 mb-3" method="get"><div class="row g-2"><div class="col-md-5"><input class="form-control" name="q" value="<?php echo esc($_GET['q']??''); ?>" placeholder="Search title, number, tags"></div><div class="col-md-4"><select class="form-select" name="module"><option value="">All modules</option><?php foreach(documentModuleOptions() as $k=>$v): ?><option value="<?php echo esc($k); ?>" <?php echo ($_GET['module']??'')===$k?'selected':''; ?>><?php echo esc($v); ?></option><?php endforeach; ?></select></div><div class="col-md-3"><button class="btn btn-outline-primary w-100">Filter</button></div></div></form><div class="table-wrap table-responsive"><table class="table align-middle"><thead><tr><th>Document</th><th>Folder/Category</th><th>Linked</th><th>Expiry</th><th>Status</th></tr></thead><tbody><?php foreach($docs as $d): ?><tr><td><strong><?php echo esc($d['document_number']); ?></strong><div><?php echo esc($d['title']); ?></div><div class="small text-secondary"><?php echo esc($d['file_name']); ?> · v<?php echo esc($d['version_number']); ?></div></td><td><?php echo esc($d['folder_name']?:'-'); ?><div class="small text-secondary"><?php echo esc($d['category_name']?:'-'); ?></div></td><td><?php echo esc($d['linked_entity_type'].' #'.$d['linked_entity_id']); ?><div class="small text-secondary"><?php echo esc($d['module_key']); ?></div></td><td><?php echo esc($d['expiry_date']?:'-'); ?></td><td><span class="badge bg-<?php echo esc(statusTone($d['approval_status'])); ?>"><?php echo esc($d['approval_status']); ?></span><br><span class="badge bg-<?php echo esc(statusTone($d['status'])); ?>"><?php echo esc($d['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>